# Category: datastore_security

from elasticsearch import Elasticsearch, helpers
import json

# Initialize Elasticsearch client with your cluster endpoint
es = Elasticsearch("http://localhost:9200")

# Check if the cluster has inline scripting enabled
if not es.cluster.health(index="*")["cluster_state"]["blocks"].get("inline_scripts", None):
    raise ValueError("Inline scripts are not enabled in the Elasticsearch cluster.")

# Accept script code from user input (req.json['script'])
script = json.loads(input("Enter your script code: "))

# Create search source with aggregation using dynamic script
search_source = {
    "query": {
        "match_all": {}
    },
    "size": 0,
    "aggs": {
        "agg_name": {
            "script": script,
            "params": {"param1": "value1", "param2": "value2"}
        }
    }
}

# Execute the search using Elasticsearch Search Helper
result = helpers.scan(es, index="your_index_name", body=search_source)

# Print aggregation results
for bucket in result["aggregations"]["agg_name"]["buckets"]:
    print(bucket["key"], bucket["doc_count"])